fn set_cli_field(fields: &mut Vec<(String, String)>, key: &str, value: impl Into<String>) {
    if let Some((_, existing)) = fields.iter_mut().find(|(field, _)| field == key) {
        *existing = value.into();
    } else {
        fields.push((key.to_string(), value.into()));
    }
}

