fn apply_in_subquery_temporal_literal_column_coercions(
    predicate: &ParsedPredicate,
    source: &mut CsvSourceData,
) -> Result<(), ShardLoomError> {
    apply_in_subquery_date_literal_column_coercions(predicate, source)?;
    apply_in_subquery_timestamp_literal_column_coercions(predicate, source)
}

fn row_value_tuples_contain_literal<F>(tuples: &[Vec<ScalarValue>], matches: F) -> bool
where
    F: Fn(&ScalarValue) -> bool,
{
    tuples.iter().flatten().any(matches)
}

fn row_value_literal_column_indexes<F>(tuples: &[Vec<ScalarValue>], matches: F) -> Vec<usize>
where
    F: Fn(&ScalarValue) -> bool,
{
    let Some(arity) = tuples.first().map(Vec::len) else {
        return Vec::new();
    };
    (0..arity)
        .filter(|column_index| {
            tuples
                .iter()
                .any(|tuple| tuple.get(*column_index).is_some_and(&matches))
        })
        .collect()
}

fn apply_in_subquery_date_literal_column_coercions(
    predicate: &ParsedPredicate,
    source: &mut CsvSourceData,
) -> Result<(), ShardLoomError> {
    match predicate {
        ParsedPredicate::Compare {
            column,
            value: ScalarValue::Date32(_),
            ..
        }
        | ParsedPredicate::DateArithmeticCompare {
            column,
            value: ScalarValue::Date32(_),
            ..
        }
        | ParsedPredicate::DateExtractCompare { column, .. } => {
            coerce_source_column_to_date32(source, column)
        }
        ParsedPredicate::InList { column, values }
            if values
                .iter()
                .any(|value| matches!(value, ScalarValue::Date32(_))) =>
        {
            coerce_source_column_to_date32(source, column)
        }
        ParsedPredicate::InSubquery { column, subquery }
        | ParsedPredicate::QuantifiedSubquery {
            column, subquery, ..
        } if subquery
            .values
            .iter()
            .any(|value| matches!(value, ScalarValue::Date32(_))) =>
        {
            coerce_source_column_to_date32(source, column)
        }
        ParsedPredicate::RowValueInList { columns, tuples }
            if row_value_tuples_contain_literal(tuples, |value| {
                matches!(value, ScalarValue::Date32(_))
            }) =>
        {
            for column_index in row_value_literal_column_indexes(tuples, |value| {
                matches!(value, ScalarValue::Date32(_))
            }) {
                coerce_source_column_to_date32(source, &columns[column_index])?;
            }
            Ok(())
        }
        ParsedPredicate::RowValueInSubquery { columns, subquery }
            if row_value_tuples_contain_literal(&subquery.tuples, |value| {
                matches!(value, ScalarValue::Date32(_))
            }) =>
        {
            for column_index in row_value_literal_column_indexes(&subquery.tuples, |value| {
                matches!(value, ScalarValue::Date32(_))
            }) {
                coerce_source_column_to_date32(source, &columns[column_index])?;
            }
            Ok(())
        }
        ParsedPredicate::Logical { left, right, .. } => {
            apply_in_subquery_date_literal_column_coercions(left, source)?;
            apply_in_subquery_date_literal_column_coercions(right, source)
        }
        ParsedPredicate::Not { inner } => {
            apply_in_subquery_date_literal_column_coercions(inner, source)
        }
        ParsedPredicate::All
        | ParsedPredicate::Compare { .. }
        | ParsedPredicate::ColumnCompare { .. }
        | ParsedPredicate::CastCompare { .. }
        | ParsedPredicate::NumericArithmeticCompare { .. }
        | ParsedPredicate::NumericAbsCompare { .. }
        | ParsedPredicate::NumericRoundingCompare { .. }
        | ParsedPredicate::GenericExpressionCompare { .. }
        | ParsedPredicate::DateArithmeticCompare { .. }
        | ParsedPredicate::TimestampArithmeticCompare { .. }
        | ParsedPredicate::StringLengthCompare { .. }
        | ParsedPredicate::TimestampExtractCompare { .. }
        | ParsedPredicate::StringTransformCompare { .. }
        | ParsedPredicate::StringFunctionCompare { .. }
        | ParsedPredicate::BooleanPredicate { .. }
        | ParsedPredicate::IsNull { .. }
        | ParsedPredicate::IsNotNull { .. }
        | ParsedPredicate::InList { .. }
        | ParsedPredicate::RowValueInList { .. }
        | ParsedPredicate::RowValueInSubquery { .. }
        | ParsedPredicate::InSubquery { .. }
        | ParsedPredicate::QuantifiedSubquery { .. }
        | ParsedPredicate::ExistsSubquery { .. }
        | ParsedPredicate::StringMatch { .. }
        | ParsedPredicate::BinaryHelperCompare { .. }
        | ParsedPredicate::BinaryByteLengthCompare { .. } => Ok(()),
    }
}

fn apply_in_subquery_timestamp_literal_column_coercions(
    predicate: &ParsedPredicate,
    source: &mut CsvSourceData,
) -> Result<(), ShardLoomError> {
    match predicate {
        ParsedPredicate::Compare {
            column,
            value: ScalarValue::TimestampMicros(_),
            ..
        }
        | ParsedPredicate::TimestampArithmeticCompare {
            column,
            value: ScalarValue::TimestampMicros(_),
            ..
        }
        | ParsedPredicate::TimestampExtractCompare { column, .. } => {
            coerce_source_column_to_timestamp_micros(source, column)
        }
        ParsedPredicate::CastCompare {
            column,
            target_dtype: LogicalDType::TimestampMicros,
            ..
        } => coerce_source_column_to_timestamp_micros(source, column),
        ParsedPredicate::InList { column, values }
            if values
                .iter()
                .any(|value| matches!(value, ScalarValue::TimestampMicros(_))) =>
        {
            coerce_source_column_to_timestamp_micros(source, column)
        }
        ParsedPredicate::InSubquery { column, subquery }
        | ParsedPredicate::QuantifiedSubquery {
            column, subquery, ..
        } if subquery
            .values
            .iter()
            .any(|value| matches!(value, ScalarValue::TimestampMicros(_))) =>
        {
            coerce_source_column_to_timestamp_micros(source, column)
        }
        ParsedPredicate::RowValueInList { columns, tuples }
            if row_value_tuples_contain_literal(tuples, |value| {
                matches!(value, ScalarValue::TimestampMicros(_))
            }) =>
        {
            for column_index in row_value_literal_column_indexes(tuples, |value| {
                matches!(value, ScalarValue::TimestampMicros(_))
            }) {
                coerce_source_column_to_timestamp_micros(source, &columns[column_index])?;
            }
            Ok(())
        }
        ParsedPredicate::RowValueInSubquery { columns, subquery }
            if row_value_tuples_contain_literal(&subquery.tuples, |value| {
                matches!(value, ScalarValue::TimestampMicros(_))
            }) =>
        {
            for column_index in row_value_literal_column_indexes(&subquery.tuples, |value| {
                matches!(value, ScalarValue::TimestampMicros(_))
            }) {
                coerce_source_column_to_timestamp_micros(source, &columns[column_index])?;
            }
            Ok(())
        }
        ParsedPredicate::Logical { left, right, .. } => {
            apply_in_subquery_timestamp_literal_column_coercions(left, source)?;
            apply_in_subquery_timestamp_literal_column_coercions(right, source)
        }
        ParsedPredicate::Not { inner } => {
            apply_in_subquery_timestamp_literal_column_coercions(inner, source)
        }
        ParsedPredicate::All
        | ParsedPredicate::Compare { .. }
        | ParsedPredicate::ColumnCompare { .. }
        | ParsedPredicate::CastCompare { .. }
        | ParsedPredicate::NumericArithmeticCompare { .. }
        | ParsedPredicate::NumericAbsCompare { .. }
        | ParsedPredicate::NumericRoundingCompare { .. }
        | ParsedPredicate::GenericExpressionCompare { .. }
        | ParsedPredicate::DateArithmeticCompare { .. }
        | ParsedPredicate::TimestampArithmeticCompare { .. }
        | ParsedPredicate::DateExtractCompare { .. }
        | ParsedPredicate::StringLengthCompare { .. }
        | ParsedPredicate::StringTransformCompare { .. }
        | ParsedPredicate::StringFunctionCompare { .. }
        | ParsedPredicate::BooleanPredicate { .. }
        | ParsedPredicate::IsNull { .. }
        | ParsedPredicate::IsNotNull { .. }
        | ParsedPredicate::InList { .. }
        | ParsedPredicate::RowValueInList { .. }
        | ParsedPredicate::RowValueInSubquery { .. }
        | ParsedPredicate::InSubquery { .. }
        | ParsedPredicate::QuantifiedSubquery { .. }
        | ParsedPredicate::ExistsSubquery { .. }
        | ParsedPredicate::StringMatch { .. }
        | ParsedPredicate::BinaryHelperCompare { .. }
        | ParsedPredicate::BinaryByteLengthCompare { .. } => Ok(()),
    }
}

fn selected_row_indexes(
    parsed: &ParsedSqlLocalSource,
    source: &CsvSourceData,
    source_format_override: Option<LocalSourceFormat>,
) -> Result<Vec<usize>, ShardLoomError> {
    selected_predicate_row_indexes(
        &parsed.predicate,
        &source.rows,
        "SQL local-source predicate evaluation failed",
        source_format_override,
    )
}

fn selected_predicate_row_indexes(
    predicate: &ParsedPredicate,
    rows: &[ExpressionInputRow],
    diagnostic_context: &str,
    source_format_override: Option<LocalSourceFormat>,
) -> Result<Vec<usize>, ShardLoomError> {
    if predicate.is_all() {
        return Ok((0..rows.len()).collect());
    }
    if predicate.uses_outer_correlation() {
        return selected_correlated_predicate_row_indexes(
            predicate,
            rows,
            diagnostic_context,
            source_format_override,
        );
    }
    let predicate_expression = predicate.to_expression()?;
    let filter = evaluate_filter(&predicate_expression, rows);
    if filter.has_errors() {
        return Err(unsupported_sql_error(&format!(
            "{}: {}",
            diagnostic_context,
            filter
                .diagnostics
                .first()
                .map_or("unknown diagnostic", |diagnostic| diagnostic
                    .reason
                    .as_deref()
                    .unwrap_or(diagnostic.message.as_str()))
        )));
    }
    Ok(filter.selected_row_indexes)
}

fn selected_correlated_predicate_row_indexes(
    predicate: &ParsedPredicate,
    rows: &[ExpressionInputRow],
    diagnostic_context: &str,
    source_format_override: Option<LocalSourceFormat>,
) -> Result<Vec<usize>, ShardLoomError> {
    let mut selected = Vec::new();
    for (row_index, row) in rows.iter().enumerate() {
        let mut row_predicate = predicate.clone();
        materialize_correlated_subquery_predicates(
            &mut row_predicate,
            row,
            source_format_override,
        )?;
        let predicate_expression = row_predicate.to_expression()?;
        let filter = evaluate_filter(&predicate_expression, std::slice::from_ref(row));
        if filter.has_errors() {
            return Err(ShardLoomError::InvalidOperation(format!(
                "{}: {}",
                diagnostic_context,
                filter
                    .diagnostics
                    .first()
                    .map_or("unknown diagnostic", |diagnostic| diagnostic
                        .reason
                        .as_deref()
                        .unwrap_or(diagnostic.message.as_str()))
            )));
        }
        if !filter.selected_row_indexes.is_empty() {
            selected.push(row_index);
        }
    }
    Ok(selected)
}

fn selected_subquery_row_indexes(
    predicate: &ParsedPredicate,
    source: &CsvSourceData,
    diagnostic_context: &str,
) -> Result<Vec<usize>, ShardLoomError> {
    if predicate.is_all() {
        return Ok((0..source.rows.len()).collect());
    }
    let predicate_expression = predicate.to_expression()?;
    let filter = evaluate_filter(&predicate_expression, &source.rows);
    if filter.has_errors() {
        return Err(ShardLoomError::InvalidOperation(format!(
            "{}: {}",
            diagnostic_context,
            filter
                .diagnostics
                .first()
                .map_or("unknown diagnostic", |diagnostic| diagnostic
                    .reason
                    .as_deref()
                    .unwrap_or(diagnostic.message.as_str()))
        )));
    }
    Ok(filter.selected_row_indexes)
}

fn selected_input_rows<'a>(
    source: &'a CsvSourceData,
    selected_row_indexes: &[usize],
) -> Result<Vec<&'a ExpressionInputRow>, ShardLoomError> {
    selected_row_indexes
        .iter()
        .map(|row_index| {
            source.rows.get(*row_index).ok_or_else(|| {
                ShardLoomError::InvalidOperation("selected row index is out of bounds".to_string())
            })
        })
        .collect()
}

fn evaluate_projection_output(
    parsed: &ParsedSqlLocalSource,
    source: &CsvSourceData,
    selected_row_indexes: &[usize],
    source_format_override: Option<LocalSourceFormat>,
) -> Result<ProjectionEvaluationOutput, ShardLoomError> {
    if parsed.limit == 0 {
        return Ok(ProjectionEvaluationOutput {
            correlated_projection_outer_row_evaluation_count: 0,
            output_rows: Vec::new(),
        });
    }
    let projection_expressions = if parsed.has_correlated_projection_predicate() {
        None
    } else {
        Some(projection_expressions(parsed, source)?)
    };
    let mut output_rows = Vec::new();
    let mut distinct_keys = BTreeSet::new();
    let mut correlated_projection_outer_row_evaluation_count = 0usize;
    for row_index in selected_row_indexes {
        let row = source.rows.get(*row_index).ok_or_else(|| {
            ShardLoomError::InvalidOperation("selected row index is out of bounds".to_string())
        })?;
        if parsed.has_correlated_projection_predicate() {
            correlated_projection_outer_row_evaluation_count += 1;
        }
        let output_row = evaluate_sql_projection_row(
            parsed,
            source,
            projection_expressions.as_deref(),
            row,
            source_format_override,
        )?;
        if parsed.has_distinct_projection() && !distinct_keys.insert(row_distinct_key(&output_row))
        {
            continue;
        }
        output_rows.push(output_row);
        if output_rows.len() >= parsed.limit {
            break;
        }
    }
    Ok(ProjectionEvaluationOutput {
        correlated_projection_outer_row_evaluation_count,
        output_rows,
    })
}

fn evaluate_computed_projection_ordered_output(
    parsed: &ParsedSqlLocalSource,
    source: &CsvSourceData,
    selected_row_indexes: &[usize],
    source_format_override: Option<LocalSourceFormat>,
) -> Result<ProjectionEvaluationOutput, ShardLoomError> {
    let order_by = parsed.order_by.as_ref().ok_or_else(|| {
        ShardLoomError::InvalidOperation(
            "computed projection ordered output requested without ORDER BY".to_string(),
        )
    })?;
    let projection_expressions = if parsed.has_correlated_projection_predicate() {
        None
    } else {
        Some(projection_expressions(parsed, source)?)
    };
    let mut projected_rows = Vec::with_capacity(selected_row_indexes.len());
    let mut sort_entries = Vec::with_capacity(selected_row_indexes.len());
    let mut correlated_projection_outer_row_evaluation_count = 0usize;
    for row_index in selected_row_indexes {
        let row = source.rows.get(*row_index).ok_or_else(|| {
            ShardLoomError::InvalidOperation("selected row index is out of bounds".to_string())
        })?;
        if parsed.has_correlated_projection_predicate() {
            correlated_projection_outer_row_evaluation_count += 1;
        }
        let output_row = evaluate_sql_projection_row(
            parsed,
            source,
            projection_expressions.as_deref(),
            row,
            source_format_override,
        )?;
        let output_index = projected_rows.len();
        let values = sort_values_for_projected_or_source_row(row, &output_row, order_by)?;
        projected_rows.push(output_row);
        sort_entries.push((*row_index, output_index, values));
    }

    let family_entries = sort_entries
        .iter()
        .map(|(row_index, _output_index, values)| (*row_index, values.clone()))
        .collect::<Vec<_>>();
    validate_sort_value_families(&family_entries)?;
    sort_entries.sort_by(
        |(left_source_index, _left_output_index, left_values),
         (right_source_index, _right_output_index, right_values)| {
            let ordering = compare_order_by_values(order_by, left_values, right_values);
            ordering.then_with(|| left_source_index.cmp(right_source_index))
        },
    );

    if !parsed.has_distinct_projection() {
        let output_rows = sort_entries
            .into_iter()
            .take(parsed.limit)
            .map(|(_source_index, output_index, _values)| projected_rows[output_index].clone())
            .collect();
        return Ok(ProjectionEvaluationOutput {
            correlated_projection_outer_row_evaluation_count,
            output_rows,
        });
    }

    let mut output_rows = Vec::new();
    let mut distinct_keys = BTreeSet::new();
    if parsed.limit == 0 {
        return Ok(ProjectionEvaluationOutput {
            correlated_projection_outer_row_evaluation_count,
            output_rows,
        });
    }
    for (_source_index, output_index, _values) in sort_entries {
        let row = &projected_rows[output_index];
        if !distinct_keys.insert(row_distinct_key(row)) {
            continue;
        }
        output_rows.push(row.clone());
        if output_rows.len() >= parsed.limit {
            break;
        }
    }
    Ok(ProjectionEvaluationOutput {
        correlated_projection_outer_row_evaluation_count,
        output_rows,
    })
}

fn evaluate_window_projection_output(
    parsed: &ParsedSqlLocalSource,
    source: &CsvSourceData,
    selected_row_indexes: &[usize],
) -> Result<Vec<Vec<(String, ScalarValue)>>, ShardLoomError> {
    let window_maps = window_value_maps(parsed, source, selected_row_indexes)?;
    let mut output_rows = Vec::new();
    let row_take_count = if parsed.has_distinct_projection() {
        selected_row_indexes.len()
    } else {
        parsed.limit
    };
    for row_index in selected_row_indexes.iter().take(row_take_count) {
        let row = source.rows.get(*row_index).ok_or_else(|| {
            ShardLoomError::InvalidOperation("selected row index is out of bounds".to_string())
        })?;
        let mut output_row = Vec::new();
        for output in &parsed.projection_order {
            match output {
                ParsedProjectionOutput::Raw(column) if column == "*" => {
                    for column in &source.header {
                        let value = row.get(column).cloned().ok_or_else(|| {
                            unsupported_sql_error(&format!(
                                "projection column {column:?} is not present in the row"
                            ))
                        })?;
                        output_row.push((column.clone(), value));
                    }
                }
                ParsedProjectionOutput::Raw(column) => {
                    let value = row.get(column).cloned().ok_or_else(|| {
                        unsupported_sql_error(&format!(
                            "projection column {column:?} is not present in the row"
                        ))
                    })?;
                    output_row.push((column.clone(), value));
                }
                ParsedProjectionOutput::Window(alias) => {
                    let values = window_maps.get(alias).ok_or_else(|| {
                        ShardLoomError::InvalidOperation(format!(
                            "window projection value map missing for alias {alias:?}"
                        ))
                    })?;
                    let value = values.get(row_index).ok_or_else(|| {
                        ShardLoomError::InvalidOperation(format!(
                            "window projection value missing for selected row {row_index}"
                        ))
                    })?;
                    output_row.push((alias.clone(), value.clone()));
                }
                _ => {
                    return Err(unsupported_sql_error(
                        "window projection smoke admits raw columns plus admitted window functions only",
                    ));
                }
            }
        }
        output_rows.push(output_row);
    }
    Ok(output_rows)
}

fn window_value_maps(
    parsed: &ParsedSqlLocalSource,
    source: &CsvSourceData,
    selected_row_indexes: &[usize],
) -> Result<BTreeMap<String, BTreeMap<usize, ScalarValue>>, ShardLoomError> {
    let mut value_maps = BTreeMap::new();
    for projection in &parsed.window_projections {
        let mut partitions: BTreeMap<Vec<String>, Vec<(usize, Vec<SortValue>)>> = BTreeMap::new();
        for row_index in selected_row_indexes {
            let row = source.rows.get(*row_index).ok_or_else(|| {
                ShardLoomError::InvalidOperation("selected row index is out of bounds".to_string())
            })?;
            let partition_key = window_partition_key(row, &projection.partition_by)?;
            let sort_values =
                sort_values_for_row(row, &projection.order_by, "window ORDER BY column")?;
            partitions
                .entry(partition_key)
                .or_default()
                .push((*row_index, sort_values));
        }

        let mut projection_values = BTreeMap::new();
        for mut entries in partitions.into_values() {
            validate_sort_value_families(&entries)?;
            entries.sort_by(|(left_index, left_values), (right_index, right_values)| {
                let ordering =
                    compare_order_by_values(&projection.order_by, left_values, right_values);
                ordering.then_with(|| left_index.cmp(right_index))
            });
            projection_values.extend(window_values_for_sorted_entries(
                &projection.function,
                entries,
                source,
            )?);
        }
        value_maps.insert(projection.alias.clone(), projection_values);
    }
    Ok(value_maps)
}

fn window_values_for_sorted_entries(
    function: &WindowFunction,
    entries: Vec<(usize, Vec<SortValue>)>,
    source: &CsvSourceData,
) -> Result<BTreeMap<usize, ScalarValue>, ShardLoomError> {
    if function.is_offset() {
        return window_offset_values_for_sorted_entries(function, &entries, source);
    }
    if function.is_distribution() {
        return window_distribution_values_for_sorted_entries(function, &entries);
    }

    let mut output_values = BTreeMap::new();
    let mut previous_values: Option<Vec<SortValue>> = None;
    let mut rank_for_peer_group = 0_i64;
    let mut dense_rank = 0_i64;
    for (rank_index, (row_index, sort_values)) in entries.into_iter().enumerate() {
        let ordinal_rank = i64::try_from(rank_index + 1).map_err(|_| {
            ShardLoomError::InvalidOperation("window rank exceeded int64 bounds".to_string())
        })?;
        let is_new_peer_group = previous_values
            .as_ref()
            .is_none_or(|previous| previous != &sort_values);
        let rank = match function {
            WindowFunction::RowNumber => ordinal_rank,
            WindowFunction::Rank => {
                if is_new_peer_group {
                    rank_for_peer_group = ordinal_rank;
                }
                rank_for_peer_group
            }
            WindowFunction::DenseRank => {
                if is_new_peer_group {
                    dense_rank = dense_rank.checked_add(1).ok_or_else(|| {
                        ShardLoomError::InvalidOperation(
                            "dense window rank exceeded int64 bounds".to_string(),
                        )
                    })?;
                }
                dense_rank
            }
            WindowFunction::Lag { .. }
            | WindowFunction::Lead { .. }
            | WindowFunction::Ntile { .. }
            | WindowFunction::PercentRank
            | WindowFunction::CumeDist => unreachable!(
                "offset and distribution window functions are handled before ranking evaluation"
            ),
        };
        if is_new_peer_group {
            previous_values = Some(sort_values);
        }
        output_values.insert(row_index, ScalarValue::Int64(rank));
    }
    Ok(output_values)
}

fn window_offset_values_for_sorted_entries(
    function: &WindowFunction,
    entries: &[(usize, Vec<SortValue>)],
    source: &CsvSourceData,
) -> Result<BTreeMap<usize, ScalarValue>, ShardLoomError> {
    let mut values = BTreeMap::new();
    let value_column = function.value_column().ok_or_else(|| {
        ShardLoomError::InvalidOperation(
            "offset window function is missing its value column".to_string(),
        )
    })?;
    let offset = function.offset_rows().ok_or_else(|| {
        ShardLoomError::InvalidOperation("offset window function is missing offset".to_string())
    })?;
    for (position, (row_index, _values)) in entries.iter().enumerate() {
        let source_position = match function {
            WindowFunction::Lag { .. } => position.checked_sub(offset),
            WindowFunction::Lead { .. } => position
                .checked_add(offset)
                .filter(|candidate| *candidate < entries.len()),
            WindowFunction::RowNumber
            | WindowFunction::Rank
            | WindowFunction::DenseRank
            | WindowFunction::Ntile { .. }
            | WindowFunction::PercentRank
            | WindowFunction::CumeDist => None,
        };
        let value = if let Some(source_position) = source_position {
            let source_row_index = entries[source_position].0;
            let row = source.rows.get(source_row_index).ok_or_else(|| {
                ShardLoomError::InvalidOperation(
                    "window offset source row index is out of bounds".to_string(),
                )
            })?;
            row.get(value_column).cloned().ok_or_else(|| {
                unsupported_sql_error(&format!(
                    "window offset source column {value_column:?} is not present in the row"
                ))
            })?
        } else {
            ScalarValue::Null
        };
        values.insert(*row_index, value);
    }
    Ok(values)
}

fn window_distribution_values_for_sorted_entries(
    function: &WindowFunction,
    entries: &[(usize, Vec<SortValue>)],
) -> Result<BTreeMap<usize, ScalarValue>, ShardLoomError> {
    match function {
        WindowFunction::Ntile { bucket_count } => {
            window_ntile_values_for_sorted_entries(*bucket_count, entries)
        }
        WindowFunction::PercentRank | WindowFunction::CumeDist => {
            window_rank_distribution_values_for_sorted_entries(function, entries)
        }
        WindowFunction::RowNumber
        | WindowFunction::Rank
        | WindowFunction::DenseRank
        | WindowFunction::Lag { .. }
        | WindowFunction::Lead { .. } => Err(ShardLoomError::InvalidOperation(
            "non-distribution window function reached distribution evaluator".to_string(),
        )),
    }
}

fn window_ntile_values_for_sorted_entries(
    bucket_count: usize,
    entries: &[(usize, Vec<SortValue>)],
) -> Result<BTreeMap<usize, ScalarValue>, ShardLoomError> {
    let mut values = BTreeMap::new();
    let row_count = entries.len();
    if row_count == 0 {
        return Ok(values);
    }
    if bucket_count == 0 {
        return Err(ShardLoomError::InvalidOperation(
            "NTILE bucket count cannot be zero after parsing".to_string(),
        ));
    }
    let base_bucket_size = row_count / bucket_count;
    let larger_bucket_count = row_count % bucket_count;
    let larger_bucket_size = base_bucket_size.saturating_add(1);
    let larger_bucket_boundary = larger_bucket_count.saturating_mul(larger_bucket_size);
    for (position, (row_index, _values)) in entries.iter().enumerate() {
        let ordinal = position + 1;
        let bucket = if base_bucket_size == 0 {
            ordinal
        } else if ordinal <= larger_bucket_boundary {
            ordinal.div_ceil(larger_bucket_size)
        } else {
            let remaining_ordinal = ordinal - larger_bucket_boundary;
            larger_bucket_count + remaining_ordinal.div_ceil(base_bucket_size)
        };
        let bucket = i64::try_from(bucket).map_err(|_| {
            ShardLoomError::InvalidOperation("NTILE bucket exceeded int64 bounds".to_string())
        })?;
        values.insert(*row_index, ScalarValue::Int64(bucket));
    }
    Ok(values)
}

fn window_rank_distribution_values_for_sorted_entries(
    function: &WindowFunction,
    entries: &[(usize, Vec<SortValue>)],
) -> Result<BTreeMap<usize, ScalarValue>, ShardLoomError> {
    let mut values = BTreeMap::new();
    let row_count = entries.len();
    if row_count == 0 {
        return Ok(values);
    }

    let mut peer_start = 0_usize;
    while peer_start < row_count {
        let peer_values = &entries[peer_start].1;
        let mut peer_end = peer_start + 1;
        while peer_end < row_count && &entries[peer_end].1 == peer_values {
            peer_end += 1;
        }
        let value = match function {
            WindowFunction::PercentRank if row_count == 1 => ScalarValue::Float64(0.0),
            WindowFunction::PercentRank => {
                let numerator = usize_to_f64(peer_start);
                let denominator = usize_to_f64(row_count - 1);
                ScalarValue::Float64(numerator / denominator)
            }
            WindowFunction::CumeDist => {
                let numerator = usize_to_f64(peer_end);
                let denominator = usize_to_f64(row_count);
                ScalarValue::Float64(numerator / denominator)
            }
            _ => {
                return Err(ShardLoomError::InvalidOperation(
                    "non-rank-distribution window function reached rank distribution evaluator"
                        .to_string(),
                ));
            }
        };
        for (row_index, _values) in entries
            .iter()
            .take(peer_end)
            .skip(peer_start)
            .map(|(row_index, values)| (row_index, values))
        {
            values.insert(*row_index, value.clone());
        }
        peer_start = peer_end;
    }

    Ok(values)
}

fn window_partition_key(
    row: &ExpressionInputRow,
    partition_by: &[String],
) -> Result<Vec<String>, ShardLoomError> {
    partition_by
        .iter()
        .map(|column| {
            row.get(column)
                .map(|value| format!("{value:?}"))
                .ok_or_else(|| {
                    unsupported_sql_error(&format!(
                        "window PARTITION BY column {column:?} is not present in the row"
                    ))
                })
        })
        .collect()
}

fn evaluate_sql_projection_row(
    parsed: &ParsedSqlLocalSource,
    source: &CsvSourceData,
    prebuilt_projection_expressions: Option<&[Expression]>,
    row: &ExpressionInputRow,
    source_format_override: Option<LocalSourceFormat>,
) -> Result<Vec<(String, ScalarValue)>, ShardLoomError> {
    if let Some(projection_expressions) = prebuilt_projection_expressions {
        return evaluate_projection_row(projection_expressions, row);
    }
    let mut scoped = parsed.clone();
    materialize_correlated_projection_subquery_predicates(
        &mut scoped,
        row,
        source_format_override,
    )?;
    let projection_expressions = projection_expressions(&scoped, source)?;
    evaluate_projection_row(&projection_expressions, row)
}

fn evaluate_projection_row(
    projection_expressions: &[Expression],
    row: &ExpressionInputRow,
) -> Result<Vec<(String, ScalarValue)>, ShardLoomError> {
    let projection = evaluate_projection(projection_expressions, row);
    if projection.has_errors() {
        return Err(unsupported_sql_error(&format!(
            "SQL local-source projection evaluation failed: {}",
            projection
                .diagnostics
                .first()
                .map_or("unknown diagnostic", |diagnostic| diagnostic
                    .reason
                    .as_deref()
                    .unwrap_or(diagnostic.message.as_str()))
        )));
    }
    Ok(projection
        .projected_columns
        .into_iter()
        .map(|column| (column.name, column.value))
        .collect())
}

fn projection_expressions(
    parsed: &ParsedSqlLocalSource,
    source: &CsvSourceData,
) -> Result<Vec<Expression>, ShardLoomError> {
    ordered_projection_expressions(parsed, &source.header, "project")
}

fn ordered_projection_expressions(
    parsed: &ParsedSqlLocalSource,
    header: &[String],
    raw_expr_prefix: &str,
) -> Result<Vec<Expression>, ShardLoomError> {
    let mut expressions = Vec::new();
    for output in &parsed.projection_order {
        append_ordered_projection_expression(
            &mut expressions,
            parsed,
            output,
            header,
            raw_expr_prefix,
        )?;
    }
    Ok(expressions)
}

#[allow(clippy::too_many_lines)]
fn append_ordered_projection_expression(
    expressions: &mut Vec<Expression>,
    parsed: &ParsedSqlLocalSource,
    output: &ParsedProjectionOutput,
    header: &[String],
    raw_expr_prefix: &str,
) -> Result<(), ShardLoomError> {
    match output {
        ParsedProjectionOutput::Raw(column) if column == "*" => {
            if header.is_empty() {
                return Err(unsupported_sql_error(
                    "SELECT * is not admitted for scoped join projections",
                ));
            }
            for column in header {
                expressions.push(Expression::column(
                    ExprId::new(format!("{raw_expr_prefix}.{column}"))?,
                    ColumnRef::new(column.clone())?,
                ));
            }
        }
        ParsedProjectionOutput::Raw(column) => {
            expressions.push(Expression::column(
                ExprId::new(format!("{raw_expr_prefix}.{column}"))?,
                ColumnRef::new(column.clone())?,
            ));
        }
        ParsedProjectionOutput::Literal(alias) => expressions.push(literal_projection_expression(
            find_projection_by_alias(&parsed.literal_projections, alias, "literal projection")?,
        )?),
        ParsedProjectionOutput::Complex(alias) => expressions.push(complex_projection_expression(
            find_projection_by_alias(&parsed.complex_projections, alias, "complex projection")?,
        )?),
        ParsedProjectionOutput::Cast(alias) => expressions.push(cast_projection_expression(
            find_projection_by_alias(&parsed.cast_projections, alias, "cast projection")?,
        )?),
        ParsedProjectionOutput::NullCoalesce(alias) => expressions.push(
            null_coalesce_projection_expression(find_projection_by_alias(
                &parsed.null_coalesce_projections,
                alias,
                "null coalesce projection",
            )?)?,
        ),
        ParsedProjectionOutput::NullIf(alias) => expressions.push(nullif_projection_expression(
            find_projection_by_alias(&parsed.nullif_projections, alias, "nullif projection")?,
        )?),
        ParsedProjectionOutput::Conditional(alias) => expressions.push(
            conditional_projection_expression(find_projection_by_alias(
                &parsed.conditional_projections,
                alias,
                "conditional projection",
            )?)?,
        ),
        ParsedProjectionOutput::Predicate(alias) => {
            expressions.push(predicate_projection_expression(find_projection_by_alias(
                &parsed.predicate_projections,
                alias,
                "predicate projection",
            )?)?);
        }
        ParsedProjectionOutput::NumericArithmetic(alias) => expressions.push(
            numeric_arithmetic_projection_expression(find_projection_by_alias(
                &parsed.numeric_arithmetic_projections,
                alias,
                "numeric arithmetic projection",
            )?)?,
        ),
        ParsedProjectionOutput::NumericAbs(alias) => expressions.push(
            numeric_abs_projection_expression(find_projection_by_alias(
                &parsed.numeric_abs_projections,
                alias,
                "numeric abs projection",
            )?)?,
        ),
        ParsedProjectionOutput::NumericRounding(alias) => expressions.push(
            numeric_rounding_projection_expression(find_projection_by_alias(
                &parsed.numeric_rounding_projections,
                alias,
                "numeric rounding projection",
            )?)?,
        ),
        ParsedProjectionOutput::GenericExpression(alias) => expressions.push(
            generic_expression_projection_expression(find_projection_by_alias(
                &parsed.generic_expression_projections,
                alias,
                "generic expression projection",
            )?)?,
        ),
        ParsedProjectionOutput::DateArithmetic(alias) => expressions.push(
            date_arithmetic_projection_expression(find_projection_by_alias(
                &parsed.date_arithmetic_projections,
                alias,
                "date arithmetic projection",
            )?)?,
        ),
        ParsedProjectionOutput::TimestampArithmetic(alias) => expressions.push(
            timestamp_arithmetic_projection_expression(find_projection_by_alias(
                &parsed.timestamp_arithmetic_projections,
                alias,
                "timestamp arithmetic projection",
            )?)?,
        ),
        ParsedProjectionOutput::StringLength(alias) => expressions.push(
            string_length_projection_expression(find_projection_by_alias(
                &parsed.string_length_projections,
                alias,
                "string length projection",
            )?)?,
        ),
        ParsedProjectionOutput::StringTransform(alias) => expressions.push(
            string_transform_projection_expression(find_projection_by_alias(
                &parsed.string_transform_projections,
                alias,
                "string transform projection",
            )?)?,
        ),
        ParsedProjectionOutput::StringFunction(alias) => expressions.push(
            string_function_projection_expression(find_projection_by_alias(
                &parsed.string_function_projections,
                alias,
                "string function projection",
            )?)?,
        ),
        ParsedProjectionOutput::BinaryHelper(alias) => expressions.push(
            binary_helper_projection_expression(find_projection_by_alias(
                &parsed.binary_helper_projections,
                alias,
                "binary helper projection",
            )?)?,
        ),
        ParsedProjectionOutput::BinaryByteLength(alias) => expressions.push(
            binary_byte_length_projection_expression(find_projection_by_alias(
                &parsed.binary_byte_length_projections,
                alias,
                "binary byte length projection",
            )?)?,
        ),
        ParsedProjectionOutput::DateExtract(alias) => expressions.push(
            date_extract_projection_expression(find_projection_by_alias(
                &parsed.date_extract_projections,
                alias,
                "date extract projection",
            )?)?,
        ),
        ParsedProjectionOutput::TimestampExtract(alias) => expressions.push(
            timestamp_extract_projection_expression(find_projection_by_alias(
                &parsed.timestamp_extract_projections,
                alias,
                "timestamp extract projection",
            )?)?,
        ),
        ParsedProjectionOutput::Window(_) => {
            return Err(unsupported_sql_error(
                "window projections require the row-set window evaluator",
            ));
        }
    }
    Ok(())
}

fn find_projection_by_alias<'a, T: ProjectionAlias>(
    projections: &'a [T],
    alias: &str,
    family: &str,
) -> Result<&'a T, ShardLoomError> {
    projections
        .iter()
        .find(|projection| projection.alias() == alias)
        .ok_or_else(|| {
            ShardLoomError::InvalidOperation(format!(
                "projection order references missing {family} alias {alias:?}"
            ))
        })
}

