    fn aggregate_statement_suffix(&self, suffix: &str) -> String {
        if self.has_having() {
            format!("{suffix}_having")
        } else {
            suffix.to_string()
        }
    }

    fn aggregate_certificate_suffix(&self, suffix: &str) -> String {
        if self.has_having() {
            format!("{suffix}-having")
        } else {
            suffix.to_string()
        }
    }

    fn join_aggregate_statement_kind(&self, suffix: &str) -> String {
        let suffix = self.aggregate_statement_suffix(suffix);
        self.join_statement_kind(&suffix)
    }

    fn join_aggregate_certificate_suffix(&self, suffix: &str) -> String {
        let suffix = self.aggregate_certificate_suffix(suffix);
        self.join_certificate_suffix(&suffix)
    }

    fn join_aggregate_claim_suffix(&self, suffix: &str) -> String {
        let suffix = self.aggregate_statement_suffix(suffix);
        self.join_claim_suffix(&suffix)
    }

    fn has_literal_projection(&self) -> bool {
        !self.literal_projections.is_empty()
    }

    fn has_complex_projection(&self) -> bool {
        !self.complex_projections.is_empty()
    }

    fn complex_projection_columns(&self) -> String {
        if self.complex_projections.is_empty() {
            "not_applicable".to_string()
        } else {
            self.complex_projections
                .iter()
                .map(|projection| projection.alias.as_str())
                .collect::<Vec<_>>()
                .join(",")
        }
    }

    fn complex_projection_kinds(&self) -> String {
        if self.complex_projections.is_empty() {
            "not_applicable".to_string()
        } else {
            self.complex_projections
                .iter()
                .map(|projection| projection.kind.kind_label())
                .collect::<Vec<_>>()
                .join(",")
        }
    }

    fn complex_projection_dtypes(&self) -> String {
        if self.complex_projections.is_empty() {
            "not_applicable".to_string()
        } else {
            self.complex_projections
                .iter()
                .map(|projection| projection.kind.output_dtype().as_str().to_string())
                .collect::<Vec<_>>()
                .join(",")
        }
    }

    fn complex_projection_source_columns(&self) -> String {
        let columns = self
            .complex_projections
            .iter()
            .flat_map(|projection| projection.kind.source_columns())
            .collect::<Vec<_>>();
        if columns.is_empty() {
            "not_applicable".to_string()
        } else {
            columns.join(",")
        }
    }

    fn complex_projection_ordering_columns(&self) -> String {
        let Some(order_by) = self.order_by.as_ref() else {
            return "not_requested".to_string();
        };
        let columns = order_by
            .keys
            .iter()
            .filter(|key| {
                self.complex_projections
                    .iter()
                    .any(|projection| projection.alias == key.column)
            })
            .map(|key| key.column.as_str())
            .collect::<Vec<_>>();
        if columns.is_empty() {
            "not_requested".to_string()
        } else {
            columns.join(",")
        }
    }

    fn complex_projection_ordering_semantics(&self) -> &'static str {
        if !self.has_complex_projection() {
            return "not_applicable";
        }
        if self.complex_projection_ordering_columns() == "not_requested" {
            return "not_requested";
        }
        "admitted_canonical_structural_result_boundary_values_only"
    }

    fn has_complex_projection_ordering(&self) -> bool {
        let Some(order_by) = self.order_by.as_ref() else {
            return false;
        };
        order_by.keys.iter().any(|key| {
            self.complex_projections
                .iter()
                .any(|projection| projection.alias == key.column)
        })
    }

    fn sort_operator_family_label(&self) -> String {
        self.order_by.as_ref().map_or_else(
            || "not_applicable".to_string(),
            |order_by| {
                order_by_operator_family_label(order_by, self.has_complex_projection_ordering())
                    .to_string()
            },
        )
    }

    fn literal_projection_dtypes(&self) -> String {
        if self.literal_projections.is_empty() {
            "not_applicable".to_string()
        } else {
            self.literal_projections
                .iter()
                .map(|projection| projection.value.dtype().as_str().to_string())
                .collect::<Vec<_>>()
                .join(",")
        }
    }

    fn has_binary_literal_projection(&self) -> bool {
        self.literal_projections
            .iter()
            .any(|projection| matches!(&projection.value, ScalarValue::Binary(_)))
    }

    fn binary_literal_projection_columns(&self) -> String {
        let columns = self
            .literal_projections
            .iter()
            .filter_map(|projection| match &projection.value {
                ScalarValue::Binary(_) => Some(projection.alias.as_str()),
                _ => None,
            })
            .collect::<Vec<_>>();
        if columns.is_empty() {
            "not_applicable".to_string()
        } else {
            columns.join(",")
        }
    }

    fn binary_literal_projection_byte_counts(&self) -> String {
        let byte_counts = self
            .literal_projections
            .iter()
            .filter_map(|projection| match &projection.value {
                ScalarValue::Binary(value) => Some(value.len().to_string()),
                _ => None,
            })
            .collect::<Vec<_>>();
        if byte_counts.is_empty() {
            "not_applicable".to_string()
        } else {
            byte_counts.join(",")
        }
    }

    fn binary_literal_projection_hex_values(&self) -> String {
        let hex_values = self
            .literal_projections
            .iter()
            .filter_map(|projection| match &projection.value {
                ScalarValue::Binary(value) => Some(bytes_to_hex(value)),
                _ => None,
            })
            .collect::<Vec<_>>();
        if hex_values.is_empty() {
            "not_applicable".to_string()
        } else {
            hex_values.join(",")
        }
    }

    fn has_cast_projection(&self) -> bool {
        !self.cast_projections.is_empty()
    }

    fn has_decimal_cast(&self) -> bool {
        self.predicate.uses_decimal_cast()
            || self
                .cast_projections
                .iter()
                .any(|projection| decimal_dtype_precision_scale(&projection.target_dtype).is_some())
    }

    fn has_null_coalesce_projection(&self) -> bool {
        !self.null_coalesce_projections.is_empty()
    }

    fn has_nullif_projection(&self) -> bool {
        !self.nullif_projections.is_empty()
    }

    fn has_conditional_projection(&self) -> bool {
        !self.conditional_projections.is_empty()
    }

    fn has_predicate_projection(&self) -> bool {
        !self.predicate_projections.is_empty()
    }

    fn has_correlated_projection_predicate(&self) -> bool {
        self.conditional_projections
            .iter()
            .any(|projection| projection.predicate.uses_outer_correlation())
            || self
                .predicate_projections
                .iter()
                .any(|projection| projection.predicate.uses_outer_correlation())
    }

    fn has_numeric_arithmetic_projection(&self) -> bool {
        !self.numeric_arithmetic_projections.is_empty()
    }

    fn has_numeric_abs_projection(&self) -> bool {
        !self.numeric_abs_projections.is_empty()
    }

    fn has_numeric_rounding_projection(&self) -> bool {
        !self.numeric_rounding_projections.is_empty()
    }

    fn has_generic_expression_projection(&self) -> bool {
        !self.generic_expression_projections.is_empty()
    }

    fn has_date_arithmetic_projection(&self) -> bool {
        !self.date_arithmetic_projections.is_empty()
    }

    fn has_timestamp_arithmetic_projection(&self) -> bool {
        !self.timestamp_arithmetic_projections.is_empty()
    }

    fn has_string_length_projection(&self) -> bool {
        !self.string_length_projections.is_empty()
    }

    fn has_string_transform_projection(&self) -> bool {
        !self.string_transform_projections.is_empty()
    }

    fn has_string_function_projection(&self) -> bool {
        !self.string_function_projections.is_empty()
    }

    fn has_binary_helper_projection(&self) -> bool {
        !self.binary_helper_projections.is_empty()
    }

    fn has_binary_byte_length_projection(&self) -> bool {
        !self.binary_byte_length_projections.is_empty()
    }

    fn has_date_extract_projection(&self) -> bool {
        !self.date_extract_projections.is_empty()
    }

    fn has_timestamp_extract_projection(&self) -> bool {
        !self.timestamp_extract_projections.is_empty()
    }

    fn has_window_projection(&self) -> bool {
        !self.window_projections.is_empty()
    }

    fn has_computed_projection(&self) -> bool {
        self.has_literal_projection()
            || self.has_complex_projection()
            || self.has_cast_projection()
            || self.has_null_coalesce_projection()
            || self.has_nullif_projection()
            || self.has_conditional_projection()
            || self.has_predicate_projection()
            || self.has_numeric_arithmetic_projection()
            || self.has_numeric_abs_projection()
            || self.has_numeric_rounding_projection()
            || self.has_generic_expression_projection()
            || self.has_date_arithmetic_projection()
            || self.has_timestamp_arithmetic_projection()
            || self.has_string_length_projection()
            || self.has_string_transform_projection()
            || self.has_string_function_projection()
            || self.has_binary_helper_projection()
            || self.has_binary_byte_length_projection()
            || self.has_date_extract_projection()
            || self.has_timestamp_extract_projection()
    }

    fn has_computed_projection_output(&self, column: &str) -> bool {
        self.projection_order
            .iter()
            .any(|output| output.computed_alias().is_some_and(|alias| alias == column))
    }

    fn join_projection_shape(&self) -> Option<JoinProjectionShape> {
        if !self.is_join() || self.is_aggregate() {
            return None;
        }
        match (
            self.has_computed_projection(),
            self.order_by.is_some(),
            self.has_filter(),
        ) {
            (true, true, true) => Some(JoinProjectionShape::ComputedTopNFilter),
            (true, true, false) => Some(JoinProjectionShape::ComputedTopN),
            (false, true, true) => Some(JoinProjectionShape::RawTopNFilter),
            (false, true, false) => Some(JoinProjectionShape::RawTopN),
            (true, false, true) => Some(JoinProjectionShape::ComputedFilter),
            (true, false, false) => Some(JoinProjectionShape::Computed),
            (false, false, _) => None,
        }
    }

    fn join_statement_kind(&self, suffix: &str) -> String {
        let join = self
            .join
            .as_ref()
            .expect("join statement kind requested without join");
        format!("local_source_{}_{}", join.statement_join_prefix(), suffix)
    }

    fn join_certificate_suffix(&self, suffix: &str) -> String {
        let join = self
            .join
            .as_ref()
            .expect("join certificate suffix requested without join");
        format!("{}-{}", join.certificate_join_prefix(), suffix)
    }

    fn join_claim_suffix(&self, suffix: &str) -> String {
        let join = self
            .join
            .as_ref()
            .expect("join claim suffix requested without join");
        format!("{}_{}", join.claim_join_prefix(), suffix)
    }

    fn statement_kind(&self) -> String {
        if self.has_distinct_projection() {
            self.distinct_projection_statement_kind()
        } else if self.is_join()
            && self.is_grouped_aggregate()
            && self.order_by.is_some()
            && self.has_filter()
        {
            self.join_aggregate_statement_kind("group_by_aggregate_order_by_topn_filter_limit")
        } else if self.is_join() && self.is_grouped_aggregate() && self.order_by.is_some() {
            self.join_aggregate_statement_kind("group_by_aggregate_order_by_topn_limit")
        } else if self.is_join()
            && self.is_aggregate()
            && self.order_by.is_some()
            && self.has_filter()
        {
            self.join_aggregate_statement_kind("aggregate_order_by_topn_filter_limit")
        } else if self.is_join() && self.is_aggregate() && self.order_by.is_some() {
            self.join_aggregate_statement_kind("aggregate_order_by_topn_limit")
        } else if self.is_join() && self.is_grouped_aggregate() && self.has_filter() {
            self.join_aggregate_statement_kind("group_by_aggregate_filter_limit")
        } else if self.is_join() && self.is_grouped_aggregate() {
            self.join_aggregate_statement_kind("group_by_aggregate_limit")
        } else if self.is_join() && self.is_aggregate() && self.has_filter() {
            self.join_aggregate_statement_kind("aggregate_filter_limit")
        } else if self.is_join() && self.is_aggregate() {
            self.join_aggregate_statement_kind("aggregate_limit")
        } else if let Some(shape) = self.join_projection_shape() {
            self.join_statement_kind(shape.statement_suffix())
        } else if self.is_join() && self.has_filter() {
            self.join_statement_kind("filter_limit")
        } else if self.is_join() {
            self.join_statement_kind("limit")
        } else if self.is_grouped_aggregate() && self.order_by.is_some() && self.has_filter() {
            format!(
                "local_source_{}",
                self.aggregate_statement_suffix("group_by_aggregate_order_by_topn_filter_limit")
            )
        } else if self.is_grouped_aggregate() && self.order_by.is_some() {
            format!(
                "local_source_{}",
                self.aggregate_statement_suffix("group_by_aggregate_order_by_topn_limit")
            )
        } else if self.is_aggregate() && self.order_by.is_some() && self.has_filter() {
            format!(
                "local_source_{}",
                self.aggregate_statement_suffix("aggregate_order_by_topn_filter_limit")
            )
        } else if self.is_aggregate() && self.order_by.is_some() {
            format!(
                "local_source_{}",
                self.aggregate_statement_suffix("aggregate_order_by_topn_limit")
            )
        } else if self.has_window_projection() && self.has_filter() {
            "local_source_window_filter_limit".to_string()
        } else if self.has_window_projection() {
            "local_source_window_limit".to_string()
        } else if let Some(kind) = self.complex_projection_statement_kind() {
            kind.to_string()
        } else if self.has_computed_projection() && self.order_by.is_some() && self.has_filter() {
            "local_source_computed_projection_order_by_topn_filter_limit".to_string()
        } else if self.has_computed_projection() && self.order_by.is_some() {
            "local_source_computed_projection_order_by_topn_limit".to_string()
        } else if self.order_by.is_some() && self.has_filter() {
            "local_source_order_by_topn_filter_limit".to_string()
        } else if self.order_by.is_some() {
            "local_source_order_by_topn_limit".to_string()
        } else if self.is_grouped_aggregate() && self.has_filter() {
            format!(
                "local_source_{}",
                self.aggregate_statement_suffix("group_by_aggregate_filter_limit")
            )
        } else if self.is_grouped_aggregate() {
            format!(
                "local_source_{}",
                self.aggregate_statement_suffix("group_by_aggregate_limit")
            )
        } else if self.is_aggregate() && self.has_filter() {
            format!(
                "local_source_{}",
                self.aggregate_statement_suffix("aggregate_filter_limit")
            )
        } else if self.is_aggregate() {
            format!(
                "local_source_{}",
                self.aggregate_statement_suffix("aggregate_limit")
            )
        } else if self.has_literal_projection() && self.has_filter() {
            "local_source_literal_projection_filter_limit".to_string()
        } else if self.has_literal_projection() {
            "local_source_literal_projection_limit".to_string()
        } else if self.has_computed_projection() && self.has_filter() {
            "local_source_computed_projection_filter_limit".to_string()
        } else if self.has_computed_projection() {
            "local_source_computed_projection_limit".to_string()
        } else if self.has_filter() {
            "local_source_projection_filter_limit".to_string()
        } else {
            "local_source_projection_limit".to_string()
        }
    }

    fn complex_projection_statement_kind(&self) -> Option<&'static str> {
        if !self.has_complex_projection() {
            return None;
        }
        Some(if self.order_by.is_some() && self.has_filter() {
            "local_source_complex_projection_order_by_topn_filter_limit"
        } else if self.order_by.is_some() {
            "local_source_complex_projection_order_by_topn_limit"
        } else if self.has_filter() {
            "local_source_complex_projection_filter_limit"
        } else {
            "local_source_complex_projection_limit"
        })
    }

