    fn distinct_aggregate_null_semantics(&self) -> String {
        if self.has_distinct_aggregate() {
            "sql_count_distinct_ignores_nulls".to_string()
        } else {
            "not_applicable".to_string()
        }
    }

    fn having_source_columns(&self) -> String {
        if !self.has_having() {
            return "not_applicable".to_string();
        }
        let hidden_labels = self
            .having_aggregates
            .iter()
            .map(|aggregate| (aggregate.output_name(), aggregate.label()))
            .collect::<BTreeMap<_, _>>();
        self.having
            .columns()
            .into_iter()
            .map(|column| {
                hidden_labels
                    .get(column)
                    .cloned()
                    .unwrap_or_else(|| column.to_string())
            })
            .collect::<Vec<_>>()
            .join(",")
    }

