impl ParsedAggregate {
    fn output_name(&self) -> String {
        if let Some(alias) = self.alias.as_ref() {
            return alias.clone();
        }
        match (self.function, self.column.as_deref(), self.distinct) {
            (AggregateFunction::Count, None, _) => "count_all".to_string(),
            (function, Some(column), true) => {
                format!("{}_distinct_{}", function.as_str(), column)
            }
            (function, Some(column), false) => format!("{}_{}", function.as_str(), column),
            (function, None, _) => function.as_str().to_string(),
        }
    }

    fn label(&self) -> String {
        match (self.function, self.column.as_deref(), self.distinct) {
            (AggregateFunction::Count, None, _) => "count(*)".to_string(),
            (function, Some(column), true) => {
                format!("{}(DISTINCT {column})", function.as_str())
            }
            (function, Some(column), false) => format!("{}({column})", function.as_str()),
            (function, None, _) => format!("{}()", function.as_str()),
        }
    }

    fn required_column(&self) -> Result<&str, ShardLoomError> {
        self.column.as_deref().ok_or_else(|| {
            unsupported_sql_error("aggregate function requires a column in this scoped smoke")
        })
    }
}

impl AggregateFunction {
    const fn as_str(self) -> &'static str {
        match self {
            Self::Count => "count",
            Self::Sum => "sum",
            Self::Avg => "avg",
            Self::Min => "min",
            Self::Max => "max",
        }
    }
}

impl WindowFunction {
    const fn as_str(&self) -> &'static str {
        match self {
            Self::RowNumber => "row_number",
            Self::Rank => "rank",
            Self::DenseRank => "dense_rank",
            Self::Lag { .. } => "lag",
            Self::Lead { .. } => "lead",
            Self::Ntile { .. } => "ntile",
            Self::PercentRank => "percent_rank",
            Self::CumeDist => "cume_dist",
        }
    }

    const fn is_row_number(&self) -> bool {
        matches!(self, Self::RowNumber)
    }

    const fn is_rank(&self) -> bool {
        matches!(self, Self::Rank)
    }

    const fn is_dense_rank(&self) -> bool {
        matches!(self, Self::DenseRank)
    }

    const fn is_ranking(&self) -> bool {
        matches!(self, Self::RowNumber | Self::Rank | Self::DenseRank)
    }

    const fn is_lag(&self) -> bool {
        matches!(self, Self::Lag { .. })
    }

    const fn is_lead(&self) -> bool {
        matches!(self, Self::Lead { .. })
    }

    const fn is_offset(&self) -> bool {
        matches!(self, Self::Lag { .. } | Self::Lead { .. })
    }

    const fn is_distribution(&self) -> bool {
        matches!(
            self,
            Self::Ntile { .. } | Self::PercentRank | Self::CumeDist
        )
    }

    fn value_column(&self) -> Option<&str> {
        match self {
            Self::Lag { column, .. } | Self::Lead { column, .. } => Some(column.as_str()),
            Self::RowNumber
            | Self::Rank
            | Self::DenseRank
            | Self::Ntile { .. }
            | Self::PercentRank
            | Self::CumeDist => None,
        }
    }

    const fn offset_rows(&self) -> Option<usize> {
        match self {
            Self::Lag { offset, .. } | Self::Lead { offset, .. } => Some(*offset),
            Self::RowNumber
            | Self::Rank
            | Self::DenseRank
            | Self::Ntile { .. }
            | Self::PercentRank
            | Self::CumeDist => None,
        }
    }

    const fn bucket_count(&self) -> Option<usize> {
        match self {
            Self::Ntile { bucket_count } => Some(*bucket_count),
            Self::RowNumber
            | Self::Rank
            | Self::DenseRank
            | Self::Lag { .. }
            | Self::Lead { .. }
            | Self::PercentRank
            | Self::CumeDist => None,
        }
    }
}

impl ParsedOrderBy {
    fn is_multi_key(&self) -> bool {
        self.keys.len() > 1
    }

    fn columns_label(&self) -> String {
        self.keys
            .iter()
            .map(|key| key.column.as_str())
            .collect::<Vec<_>>()
            .join(",")
    }

    fn directions_label(&self) -> String {
        self.keys
            .iter()
            .map(|key| key.direction.as_str())
            .collect::<Vec<_>>()
            .join(",")
    }

    fn null_ordering_label(&self) -> String {
        if self.keys.iter().all(|key| key.null_ordering.is_none()) {
            return "nulls_blocked_for_fixture_smoke".to_string();
        }
        self.keys
            .iter()
            .map(|key| {
                key.null_ordering
                    .map_or("implicit_nulls_blocked", SortNullOrdering::as_str)
            })
            .collect::<Vec<_>>()
            .join(",")
    }

    fn operator_family_label(&self) -> &'static str {
        order_by_operator_family_label(self, false)
    }
}

fn order_by_operator_family_label(
    order_by: &ParsedOrderBy,
    includes_complex_key: bool,
) -> &'static str {
    match (order_by.is_multi_key(), includes_complex_key) {
        (true, true) => "multi_key_complex_result_boundary_topn",
        (false, true) => "single_key_complex_result_boundary_topn",
        (true, false) => "multi_key_scalar_topn",
        (false, false) => "single_key_scalar_topn",
    }
}

impl QualifiedColumn {
    fn to_ref(&self) -> String {
        qualified_column_name(&self.alias, &self.column)
    }
}

impl ParsedJoin {
    fn statement_join_prefix(&self) -> String {
        if self.uses_expression_on() {
            self.join_type.expression_statement_prefix().to_string()
        } else {
            self.join_type.statement_prefix().to_string()
        }
    }

    fn certificate_join_prefix(&self) -> String {
        if self.uses_expression_on() {
            self.join_type.expression_certificate_prefix().to_string()
        } else {
            self.join_type.certificate_prefix().to_string()
        }
    }

    fn claim_join_prefix(&self) -> String {
        if self.uses_expression_on() {
            self.join_type.expression_claim_prefix().to_string()
        } else {
            self.join_type.claim_prefix().to_string()
        }
    }

    fn kind(&self) -> String {
        if self.uses_expression_on() {
            self.join_type.expression_as_str().to_string()
        } else {
            self.join_type.as_str().to_string()
        }
    }

    fn uses_expression_on(&self) -> bool {
        self.on_predicate.is_some()
    }

    fn key_arity(&self) -> usize {
        self.key_pairs.len()
    }

    fn is_multi_key(&self) -> bool {
        self.key_arity() > 1
    }

    fn left_key_refs(&self) -> String {
        self.key_pairs
            .iter()
            .map(|pair| pair.left.to_ref())
            .collect::<Vec<_>>()
            .join(",")
    }

    fn right_key_refs(&self) -> String {
        self.key_pairs
            .iter()
            .map(|pair| pair.right.to_ref())
            .collect::<Vec<_>>()
            .join(",")
    }

    fn on_predicate_source_columns(&self) -> String {
        self.on_predicate
            .as_ref()
            .map(|predicate| predicate.columns().join(","))
            .unwrap_or_default()
    }

    fn on_predicate_family(&self) -> &'static str {
        self.on_predicate_family.as_str()
    }
}

