    #[test]
    fn runs_scoped_multi_key_order_by_topn_csv_statement() {
        let path = sql_local_source_test_path("csv");
        fs::write(
            &path,
            "id,label,amount\n1,alpha,10\n2,beta,10\n3,gamma,20\n4,delta,20\n5,epsilon,5\n6,al%pha,1\n",
        )
        .expect("write csv source");

        let request = SqlLocalSourceRequest {
            source_format_override: None,
            statement: format!(
                "SELECT id,label FROM '{}' WHERE amount >= 10 ORDER BY amount DESC,id ASC LIMIT 3",
                path.display()
            ),
            output_format: SqlLocalSourceOutputFormat::InlineJsonl,
            output_path: None,
            fanout_outputs: Vec::new(),
            allow_overwrite: false,
            runtime_profile: SqlLocalSourceRuntimeProfile::Smoke,
        };
        let report = run_local_source_runtime_single(&request).expect("run multi-key top-N smoke");
        let fields = field_map(report.fields());

        assert_eq!(
            report.result_jsonl,
            "{\"id\":3,\"label\":\"gamma\"}\n{\"id\":4,\"label\":\"delta\"}\n{\"id\":1,\"label\":\"alpha\"}\n"
        );
        assert_field_eq(&fields, "order_by_runtime_execution", "true");
        assert_field_eq(&fields, "top_n_runtime_execution", "true");
        assert_field_eq(&fields, "sort_operator_family", "multi_key_scalar_topn");
        assert_field_eq(&fields, "sort_keys", "amount,id");
        assert_field_eq(&fields, "sort_direction", "desc,asc");
        assert_field_eq(&fields, "top_n_limit", "3");
        assert_field_eq(&fields, "fallback_attempted", "false");
        assert_field_eq(&fields, "external_engine_invoked", "false");

        let comma_request = SqlLocalSourceRequest {
            source_format_override: None,
            statement: format!(
                "SELECT id,label FROM '{}' WHERE label LIKE 'al,%%' ESCAPE ',' LIMIT 10",
                path.display()
            ),
            output_format: SqlLocalSourceOutputFormat::InlineJsonl,
            output_path: None,
            fanout_outputs: Vec::new(),
            allow_overwrite: false,
            runtime_profile: SqlLocalSourceRuntimeProfile::Smoke,
        };
        let comma_report =
            run_local_source_runtime_single(&comma_request).expect("run comma ESCAPE smoke");
        let comma_fields = field_map(comma_report.fields());

        assert_eq!(
            comma_report.result_jsonl,
            "{\"id\":6,\"label\":\"al%pha\"}\n"
        );
        assert_field_eq(
            &comma_fields,
            "string_predicate_like_escape_character",
            "\",\"",
        );
        assert_field_eq(&comma_fields, "fallback_attempted", "false");
        assert_field_eq(&comma_fields, "external_engine_invoked", "false");

        fs::remove_file(&path).expect("remove csv source");
    }

